SELECT jd.id AS jd_id, jd.track_id, jd.job_id, rj.job_name, jd.enterprise_id, jd.student_user_id, su.real_name AS student_name, sr.student_no, sr.major_id, m.major_name, sr.expect_city, sr.expect_salary, sr.self_intro, sr.education_exp, sr.practice_exp, sr.certs, sr.resume_file, jd.deliver_status, jd.hr_remark, jd.deliver_time, jd.create_time AS jd_create_time FROM job_deliver jd LEFT JOIN recruit_job rj ON jd.job_id = rj.id LEFT JOIN sys_user su ON jd.student_user_id = su.id LEFT JOIN student_resume sr ON jd.student_user_id = sr.student_user_id LEFT JOIN major m ON sr.major_id = m.id
rj.teacher_user_id = #{teacherUserId}
AND jd.job_id = #{jobId}
AND jd.deliver_status = #{deliverStatus}
ORDER BY jd.create_time DESC LIMIT #{offset}, #{pageSize}

